    @WebMethod(operationName = "processPayment")
    public PaymentResponse processPayment(
            @WebParam(name = "paymentRequest") PaymentRequest paymentRequest) {

        LOGGER.info("Processing payment request: " + paymentRequest);

        PaymentResponse response = new PaymentResponse();

        try {
            if (paymentRequest == null) {
                response.setStatus("FAILED");
                response.setMessage("Payment request is null");
                response.setTransactionId(null);
                return response;
            }

            if (paymentRequest.getCardNumber() == null || paymentRequest.getCardNumber().isEmpty()) {
                response.setStatus("FAILED");
                response.setMessage("Card number is required");
                response.setTransactionId(null);
                return response;
            }

            if (paymentRequest.getAmount() <= 0) {
                response.setStatus("FAILED");
                response.setMessage("Amount must be greater than zero");
                response.setTransactionId(null);
                return response;
            }

            if (paymentRequest.getCurrency() == null || paymentRequest.getCurrency().isEmpty()) {
                response.setStatus("FAILED");
                response.setMessage("Currency is required");
                response.setTransactionId(null);
                return response;
            }

            String transactionId = UUID.randomUUID().toString();

            String maskedCard = maskCardNumber(paymentRequest.getCardNumber());
            LOGGER.info("Processing payment for card: " + maskedCard +
                    ", Amount: " + paymentRequest.getAmount() +
                    " " + paymentRequest.getCurrency());

            boolean paymentSuccess = simulatePaymentProcessing(paymentRequest);

            if (paymentSuccess) {
                response.setStatus("SUCCESS");
                response.setMessage("Payment processed successfully");
                response.setTransactionId(transactionId);
                response.setAmount(paymentRequest.getAmount());
                response.setCurrency(paymentRequest.getCurrency());
            } else {
                response.setStatus("DECLINED");
                response.setMessage("Payment was declined by the issuing bank");
                response.setTransactionId(transactionId);
            }

        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Error processing payment", e);
            response.setStatus("ERROR");
            response.setMessage("Internal processing error: " + e.getMessage());
        }

        return response;
    }

    @WebMethod(operationName = "refundPayment")
    public PaymentResponse refundPayment(
            @WebParam(name = "transactionId") String transactionId,
            @WebParam(name = "amount") double amount) {

        LOGGER.info("Processing refund for transaction: " + transactionId);

        PaymentResponse response = new PaymentResponse();

        if (transactionId == null || transactionId.isEmpty()) {
            response.setStatus("FAILED");
            response.setMessage("Transaction ID is required for refund");
            return response;
        }

        if (amount <= 0) {
            response.setStatus("FAILED");
            response.setMessage("Refund amount must be greater than zero");
            return response;
        }

        response.setStatus("SUCCESS");
        response.setMessage("Refund processed successfully");
        response.setTransactionId(UUID.randomUUID().toString());
        response.setAmount(amount);

        return response;
    }

    @WebMethod(operationName = "getTransactionStatus")
    public PaymentResponse getTransactionStatus(
            @WebParam(name = "transactionId") String transactionId) {

        LOGGER.info("Checking status for transaction: " + transactionId);

        PaymentResponse response = new PaymentResponse();
        response.setTransactionId(transactionId);
        response.setStatus("COMPLETED");
        response.setMessage("Transaction found and completed");

        return response;
    }

    private boolean simulatePaymentProcessing(PaymentRequest request) {
        if (request.getCardNumber().startsWith("4111")) {
            return true;
        }
        if (request.getCardNumber().startsWith("4000")) {
            return false;
        }
        return request.getAmount() < 10000;
    }

    private String maskCardNumber(String cardNumber) {
        if (cardNumber == null || cardNumber.length() < 4) {
            return "****";
        }
        String last4 = cardNumber.substring(cardNumber.length() - 4);
        return "****-****-****-" + last4;
    }

